class SecureJsonSerde:
    """
    Custom serializer/deserializer that includes HMAC for integrity verification.
    This prevents cache poisoning attacks where an attacker might inject
    malicious data into memcached.
    """

    def __init__(self, hmac_key: str):
        self._hmac_key = hmac_key.encode('utf-8')

    def serialize(self, key: str, value: Any) -> tuple:
        """Serialize value with HMAC integrity tag."""
        payload = json.dumps(value, default=str)
        mac = hmac.new(self._hmac_key, payload.encode('utf-8'), hashlib.sha256).hexdigest()
        tagged = json.dumps({'payload': payload, 'mac': mac})
        return tagged.encode('utf-8'), 1

    def deserialize(self, key: str, value: bytes, flags: int) -> Optional[Any]:
        """Deserialize and verify HMAC integrity."""
        try:
            tagged = json.loads(value.decode('utf-8'))
            payload = tagged.get('payload')
            mac = tagged.get('mac')

            if not payload or not mac:
                logger.warning("Cache entry missing payload or MAC for key pattern")
                return None

            expected_mac = hmac.new(
                self._hmac_key, payload.encode('utf-8'), hashlib.sha256
            ).hexdigest()

            if not hmac.compare_digest(mac, expected_mac):
                logger.warning("Cache integrity check failed - possible tampering detected")
                return None

            return json.loads(payload)
        except (json.JSONDecodeError, UnicodeDecodeError, KeyError) as e:
            logger.warning("Failed to deserialize cache entry: %s", type(e).__name__)
            return None


