def verify_api_key(provided_key: str) -> bool:
    """
    Verify API key using constant-time comparison against stored hash.
    The actual API key is never stored - only its hash.
    """
    if not provided_key or not isinstance(provided_key, str):
        return False

    provided_hash = hashlib.sha256(provided_key.encode('utf-8')).hexdigest()
    stored_hash = app.config.get('API_KEY_HASH', '')

    return hmac.compare_digest(provided_hash, stored_hash)


def require_api_key(f):
    """Decorator to require API key authentication."""
    @wraps(f)
    def decorated(*args, **kwargs):
        api_key = request.headers.get('X-API-Key', '')

        if not verify_api_key(api_key):
            logger.warning("Authentication failed from IP: %s", request.remote_addr)
            abort(401, description="Invalid or missing API key")

        return f(*args, **kwargs)
    return decorated


