def validate_query_params(params: dict, allowed_keys: set) -> dict:
    """Validate query parameters against an explicit allowlist."""
    validated = {}
    for key, value in params.items():
        if key not in allowed_keys:
            logger.warning("Rejected unknown query parameter: %s", key)
            continue

        # Sanitize string values
        if isinstance(value, str):
            # Remove any control characters
            value = re.sub(r'[\x00-\x1f\x7f-\x9f]', '', value)
            # Limit length
            if len(value) > 1000:
                raise ValueError(f"Parameter '{key}' exceeds maximum length")

        validated[key] = value

    return validated


