def cached_response(ttl: int = None, key_prefix: str = ''):
    """
    Decorator to cache API responses.
    Generates cache key from request path and validated query parameters.
    """
    def decorator(f):
        @wraps(f)
        def decorated(*args, **kwargs):
            effective_ttl = ttl or app.config['CACHE_TTL_MEDIUM']

            # Build cache key from request details
            cache_key_parts = [
                key_prefix or f.__name__,
                request.path,
                str(sorted(request.args.items())),
            ]
            cache_key = ':'.join(cache_key_parts)

            # Try to get from cache
            cached = cache.get(cache_key)
            if cached is not None:
                response = jsonify(cached)
                response.headers['X-Cache'] = 'HIT'
                return response

            # Execute the function
            result = f(*args, **kwargs)

            # Cache the result
            if isinstance(result, tuple):
                data, status_code = result[0], result[1] if len(result) > 1 else 200
            else:
                data = result
                status_code = 200

            # Only cache successful responses
            if status_code == 200:
                response_data = data.get_json() if hasattr(data, 'get_json') else data
                cache.set(cache_key, response_data, ttl=effective_ttl)

            if hasattr(data, 'headers'):
                data.headers['X-Cache'] = 'MISS'

            return result

        return decorated
    return decorator


