# --- Rate Limiting ---

class RateLimiter:
    """Simple rate limiter using memcached."""

    def __init__(self, cache_client: SecureMemcachedClient, max_requests: int = 100, window: int = 60):
        self._cache = cache_client
        self._max_requests = max_requests
        self._window = window

    def is_allowed(self, identifier: str) -> bool:
        """Check if request is allowed under rate limit."""
        key = f"ratelimit:{identifier}"
        current = self._cache.get(key)

        if current is None:
            self._cache.set(key, {'count': 1, 'start': time.time()}, ttl=self._window)
            return True

        if isinstance(current, dict):
            count = current.get('count', 0)
            if count >= self._max_requests:
                return False
            current['count'] = count + 1
            self._cache.set(key, current, ttl=self._window)
            return True

        return True


rate_limiter = RateLimiter(cache, max_requests=100, window=60)


